/* Test driver */
public class Main {
    public static void main(String[] args) {
        LRUCache<String> lru = new LRUCache<>(2);
        lru.put("a","A"); lru.put("b","B");
        lru.get("a");
        lru.put("c","C");
        System.out.println(lru.get("b") == null ? "OK_LRU_EVICT_B" : "FAIL");
        System.out.println(lru.get("a") != null ? "OK_LRU_KEEP_A" : "FAIL");
    }
}

