/* Test driver */
public class Main {
    public static void main(String[] args) throws InterruptedException {
        LRUCache<String> base = new LRUCache<>(4);
        TTLCache<String> ttl = new TTLCache<>(base, 100);
        ttl.put("k", "v");
        System.out.println(ttl.get("k") != null ? "OK_TTL_FRESH" : "FAIL");
        Thread.sleep(150);
        System.out.println(ttl.get("k") == null ? "OK_TTL_EXPIRED" : "FAIL");
    }
}

